class Solution:
    def minValidStrings(self, words, target):
        m = len(target)
        INF = float('inf')
        dp = [INF] * (m + 1)
        dp[0] = 0
        for i in range(m):
            if dp[i] == INF:
                continue
            for w in words:
                max_len = min(len(w), m - i)
                length = 0
                while length < max_len and w[length] == target[i + length]:
                    length += 1
                for step in range(1, length + 1):
                    if dp[i] + 1 < dp[i + step]:
                        dp[i + step] = dp[i] + 1
        return dp[m] if dp[m] != INF else -1

