class Solution:
    def minValidStrings(self, words, target):
        m = len(target)
        reach = [0] * m

        def z_function(s):
            n = len(s)
            z = [0] * n
            l, r = 0, 0
            for i in range(1, n):
                if i < r:
                    z[i] = min(r - i, z[i - l])
                while i + z[i] < n and s[z[i]] == s[i + z[i]]:
                    z[i] += 1
                if i + z[i] > r:
                    l, r = i, i + z[i]
            return z

        for w in words:
            combined = w + chr(0) + target
            z = z_function(combined)
            wl = len(w)
            for i in range(m):
                L = min(z[wl + 1 + i], wl)
                if L > reach[i]:
                    reach[i] = L

        if reach[0] == 0:
            return -1
        jumps = 1
        cur_end = reach[0]
        if cur_end >= m:
            return jumps
        farthest = cur_end
        i = 1
        while cur_end < m:
            while i <= cur_end:
                farthest = max(farthest, i + reach[i])
                i += 1
            if farthest <= cur_end:
                return -1
            jumps += 1
            cur_end = farthest
        return jumps

