function zFunction(s) {
    const n = s.length;
    const z = new Array(n).fill(0);
    let l = 0, r = 0;
    for (let i = 1; i < n; i++) {
        if (i < r) z[i] = Math.min(r - i, z[i - l]);
        while (i + z[i] < n && s[z[i]] === s[i + z[i]]) z[i]++;
        if (i + z[i] > r) { l = i; r = i + z[i]; }
    }
    return z;
}

var minValidStrings = function(words, target) {
    const m = target.length;
    const reach = new Array(m).fill(0);
    for (const w of words) {
        const combined = w + '\u0000' + target;
        const z = zFunction(combined);
        const wl = w.length;
        for (let i = 0; i < m; i++) {
            const L = Math.min(z[wl + 1 + i], wl);
            if (L > reach[i]) reach[i] = L;
        }
    }
    if (reach[0] === 0) return -1;
    let jumps = 1;
    let curEnd = reach[0];
    if (curEnd >= m) return jumps;
    let farthest = curEnd;
    let i = 1;
    while (curEnd < m) {
        while (i <= curEnd) {
            farthest = Math.max(farthest, i + reach[i]);
            i++;
        }
        if (farthest <= curEnd) return -1;
        jumps++;
        curEnd = farthest;
    }
    return jumps;
};
